document.addEventListener("DOMContentLoaded",function(){const marquee=document.querySelector(".brand-logos-marquee"),track=document.querySelector("[data-brand-track]");if(!marquee||!track)return;Array.from(track.children).forEach(item=>{const clone=item.cloneNode(!0);clone.setAttribute("aria-hidden","true"),track.appendChild(clone)}),marquee.addEventListener("mouseenter",function(){marquee.classList.add("is-paused")}),marquee.addEventListener("mouseleave",function(){marquee.classList.remove("is-paused")}),marquee.addEventListener("touchstart",function(){marquee.classList.add("is-paused")},{passive:!0}),marquee.addEventListener("touchend",function(){marquee.classList.remove("is-paused")})});